import{_ as t,o as r,c as a,a9 as p}from"./chunks/framework.D4xYp1Zt.js";const s="/images/10-types-of-30-year-old-single-guys/total-package1.png",o="/images/10-types-of-30-year-old-single-guys/lease-on-life.png",n="/images/10-types-of-30-year-old-single-guys/ethnicity.png",l="/images/10-types-of-30-year-old-single-guys/misogynist.png",i="/images/10-types-of-30-year-old-single-guys/peaked-early.png",g="/images/10-types-of-30-year-old-single-guys/Finally-a-Good-Catch.png",y="/images/10-types-of-30-year-old-single-guys/normal-guy1.png",h="/images/10-types-of-30-year-old-single-guys/cant-believe-not-married1.png",c="/images/10-types-of-30-year-old-single-guys/in-the-closet.png",m="/images/10-types-of-30-year-old-single-guys/quit.png",f="/images/10-types-of-30-year-old-single-guys/pinit_fg_en_rect_gray_20.png",S=JSON.parse('{"title":"10 Types of 30-Year-Old Single Guys","description":"","frontmatter":{"title":"10 Types of 30-Year-Old Single Guys","titleZh":"30岁单身男的10种类型","date":"2013-10-09T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2013/10/10-types-of-30-year-old-single-guys.html","slug":"10-types-of-30-year-old-single-guys"},"headers":[],"relativePath":"posts/10-types-of-30-year-old-single-guys.md","filePath":"posts/10-types-of-30-year-old-single-guys.md","lastUpdated":1782886257000}'),u={name:"posts/10-types-of-30-year-old-single-guys.md"};function d(_,e,b,w,k,T){return r(),a("div",null,[...e[0]||(e[0]=[p('<h1 id="_30岁单身男的10种类型-·-10-types-of-30-year-old-single-guys" tabindex="-1">30岁单身男的10种类型 · 10 Types of 30-Year-Old Single Guys <a class="header-anchor" href="#_30岁单身男的10种类型-·-10-types-of-30-year-old-single-guys" aria-label="Permalink to &quot;30岁单身男的10种类型 · 10 Types of 30-Year-Old Single Guys&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2013/10/10-types-of-30-year-old-single-guys.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2013/10/10-types-of-30-year-old-single-guys.html</a> · 2013-10-09</p></blockquote><p>30 岁的男人是一群奇怪的生物。</p><p>给我一群 30 岁的男人,我能从中挑出:一个还没长大的兄弟会大叔,和一堆室友合住;另一个刚把两个孩子送到学校的爸爸;几个事业蒸蒸日上的人;还有几个正在找工作、在寻找人生意义的迷茫哥们儿。有些人会告诉你他们终于把一切都想明白了,另一些人则会说这是他们人生中第一次感到绝望。这真是杂七杂八的一群人。</p><p>但这群人里最杂七杂八的部分,或许就是那个不断壮大的群体——30 岁单身男。如果你想做一个人类学案例研究,30 岁单身男几乎覆盖了所有的类型。让我们来看看几种常见的类型:</p><p>**</p><ol><li>完美先生 (The Total Package)**</li></ol><p><a href="https://waitbutwhy.com/wp-content/uploads/2013/10/total-package1.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt="total package"></a></p><p>完美先生很聪明——他上的是顶尖大学。完美先生是运动员、音乐家,还是个热衷旅行的人。完美先生长得帅——而且你最好相信他打扮得一丝不苟。</p><p>完美先生的事业发展得如火如荼,但你千万别暗示完美先生是个工作狂——完美先生是个顾家的男人。</p><p>只有一样东西完美先生似乎很难找到——一个配得上他伟大的女孩。</p><p>是的,配得上完美先生的女人将是他这块完美蛋糕上的最终糖霜。他经常想象她——美若天仙,回头率爆表;魅力四射、光彩照人,走进哪个房间都能点亮它;她在事业上是一颗冉冉升起的耀眼新星,深受众多朋友的喜爱。这还只是她的公开形象——在家里,她床上功夫了得,厨艺惊人,充满爱意、无私、忠诚。哦对了,她还会说法语、打网球、唱歌好听、博览群书,而且还是个历史迷。她就是他的朱丽叶。</p><p>毫不意外,完美先生是单身。他正陷入一场激烈的内心战争——他那超人般的标准 vs 他对 40 岁还单身的恐惧——因为「40 岁还单身」不该是完美先生故事的一部分。</p><p><strong>2) 重获新生哥 (The New Lease On Life Guy)</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2013/10/lease-on-life.png" target="_blank" rel="noreferrer"><img src="'+o+'" alt="lease on life"></a></p><p>从记忆所及,重获新生哥一直都在跟他的长期女友交往。他在这段关系里似乎从来没有那么开心过,但所有人都以为他们最终会结婚。现在,经历了一场漫长而痛苦的分手后,重获新生哥重出江湖、气势如虹,突然表现得像刚在《价格猜猜猜 (The Price Is Right)》上被叫到台上一样。他不太确定该怎么当一个单身汉,但他他妈的开心得不得了,而且他今晚绝对是要出去嗨的。</p><p>他还是「认命未婚夫」的头号死对头——「认命未婚夫」自己也困在一段不幸福的关系里,但就这么凑合着过下去了,抗拒不了那甜蜜、甜蜜的惯性,而且他绝对、绝对不想听「重获新生哥」最近又有什么风流韵事。</p><p>**<br> 3) 必须娶个同族裔女孩否则爸妈就再也不跟他说话的男人**</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2013/10/ethnicity.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt="ethnicity"></a></p><p>找到人生伴侣本来就够难了,而这位老兄的父母是真的一点忙都不帮。他曾短暂反抗过一次,但上一任女朋友被爸妈拒之门外、当场哭了出来之后,他就放弃挣扎了。</p><p>另外,他也真的很希望他妈别再给他安排相亲了。</p><p>**<br> 4) 厌女男**</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2013/10/misogynist.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt="misogynist"></a></p><p>厌女男讨厌女人,女人也讨厌厌女男。厌女男对异性了解得不算多,但他能精确告诉你自己睡过多少个——214 个。</p><p>年轻时他其实混得相当不错,那时候很多女生正处于「专门被混蛋吸引」的阶段。但最近,似乎只有自尊心最低的那批女生才会往他身边凑。</p><p>厌女男的近亲是「常年劈腿男」。他俩不一样,但彼此心照不宣。</p><p>**<br> 5) 巅峰来得太早的男人**</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2013/10/peaked-early.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt="peaked early"></a></p><p>想当年,「巅峰来得太早的男人」拥有一个 17 岁女孩能梦想的一切。他爆棚的自信一路把他护送穿过大学,20 岁出头就搞定了一个聪明、温柔、漂亮的女朋友,没人觉得意外。但「巅峰来得太早的男人」才刚刚开始。世界那么大,该去撒欢儿,于是他在 24 岁那年跟女朋友分了手。</p><p>如今七年过去了,他的头发觉得无聊、辞职跑路了,他高中打长曲棍球的光辉战绩最近也没什么人聊了。他还注意到,像他前女友那种类型的女生似乎不再对他感兴趣了。在所有人都看清这件事的大约五年之后,他终于也看清了,深深叹了一口气,把自己的标准往下咔咔调了好几大档。</p><p><strong>6) 终于成为优质对象的男人</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2013/10/Finally-a-Good-Catch.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt="Finally a Good Catch"></a></p><p>而在硬币的另一面,在减掉一些体重、买了像样的衣服、事业初期又小有成就之后,「终于成了抢手货的哥们」每周收获的关注,比他前 25 年加起来的都多。姑娘们觉得这么有魅力的一个男人还能保持谦逊,实在太招人喜欢——其实真相是,他一直默认每个姑娘都高攀不起。</p><p>一旦他开始意识到自己的新处境,就会进入一个令人遗憾的新阶段,让他的男性朋友们相当抓狂——比如跟姑娘跳舞时会越过对方的肩膀朝哥们儿眨眼,或者街上走过一个漂亮姑娘就要跟哥们儿碰个拳。</p><p><strong>7) 只是还没遇到对的姑娘、真心希望大家别再用那种同情眼神看他的普通哥们</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2013/10/normal-guy1.png" target="_blank" rel="noreferrer"><img src="'+y+'" alt="normal guy"></a></p><p>啊,「普通哥们」。他日子过得挺舒坦。喜欢自己的工作,喜欢自己的朋友,单身也觉得挺好。他一点儿都不着急谈恋爱,而且笃信自己迟早会遇到对的姑娘,然后结婚。</p><p>他也搞不太懂为什么所有认识他的人都在琢磨「他到底哪儿出了问题」。他爸妈忧心忡忡,一逮到机会就问他最近有没有约会。他的朋友们急着帮忙,一有机会就给他安排相亲。他很感激这些不请自来的支援,不过他也觉得,要是大家能别再觉得他有毛病,那就真的太棒了。</p><p>**<br> 8) 疯狂网上约会、却不敢相信自己居然还没结婚的哥们**</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2013/10/cant-believe-not-married1.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt="can&#39;t believe not married"></a></p><p>跟上一位刚好相反,「疯狂网上约会哥」怎么都不敢相信自己居然还没结婚。整个高中、大学以及二十几岁,他一直都是「有女朋友的那位」。他花了好几年愉快地同情那些单身的朋友,结果不知怎么的,他现在 30 岁,单身。</p><p>他有四个网上约会账号,每当有人问他有没有在跟谁约会,他就解释说自己现在忙事业,没空谈恋爱。</p><p><strong>9) 深柜哥</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2013/10/in-the-closet.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt="in the closet"></a></p><p>「深柜哥」<em>差一点点</em>就是完美对象——他长得帅、穿得好,还有份好工作。他风趣、口才好、有魅力。<em>唯一</em>的一点小小不便就是,他对女性完全没有性吸引力。</p><p>与他形成对比的是「那个不是同性恋只是还没遇到对的人现在单身也挺好的家伙 (The NGWJHMTRGYAHRWPWSLAHWTPE)」,他已经受够了那些关于他是同性恋的猜测,因为他百分之百是直的,而且已经说了一百遍——就是还没遇到对的女孩,现在单身真的完全没问题。</p><p>**<br> 10) 到这个阶段已经彻底放弃了的家伙**</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2013/10/quit.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt="quit"></a></p><p>「到这个阶段已经彻底放弃了的家伙」一开始就没怎么努力过,但至少以前还装装样子。他不喜欢去酒吧,拒绝尝试网上约会,水烟壶和 X-Box 在他四个月前被朋友训了一顿激励了一番、短暂地塞进壁橱之后,现在又都回到客厅摆着了。</p><p>内心深处,「到这个阶段已经彻底放弃了的家伙」其实对很多事情都挺害怕的,但他的恐惧表现为漠然的否认,通常被动就赢了。「到这个阶段已经彻底放弃了的家伙」只有一种可能会发生改变,那就是被「穷追猛打型女孩」牢牢锁定在射程之内。在那之前,这整件事根本就不是他的问题。</p><p>**<br> 如果你喜欢这篇,可以看看:**</p><p><a href="https://waitbutwhy.com/2014/12/10-types-odd-friendships-youre-probably-part.html" target="_blank" rel="noreferrer">你大概也身处其中的 10 种奇怪友谊</a></p><p><a href="https://waitbutwhy.com/2013/07/7-ways-to-be-insufferable-on-facebook.html" target="_blank" rel="noreferrer">在 Facebook 上让人受不了的 7 种方法</a></p><p><a href="https://waitbutwhy.com/2014/02/pick-life-partner.html" target="_blank" rel="noreferrer">如何挑选人生伴侣</a></p><h2 id="你为什么其实偷偷讨厌那些酷炫酒吧" tabindex="-1"><a href="https://waitbutwhy.com/2014/05/secretly-hate-bars.html" target="_blank" rel="noreferrer">你为什么其实偷偷讨厌那些酷炫酒吧</a> <a class="header-anchor" href="#你为什么其实偷偷讨厌那些酷炫酒吧" aria-label="Permalink to &quot;[你为什么其实偷偷讨厌那些酷炫酒吧](https://waitbutwhy.com/2014/05/secretly-hate-bars.html)&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请订阅我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章发布时我们会通知你。</p><p>想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2013/10/10-types-of-30-year-old-single-guys.html&amp;description=10%20Types%20of%2030-Year-Old%20Single%20Guys" target="_blank" rel="noreferrer"><img src="'+f+'" alt=""></a></p>',59)])])}const P=t(u,[["render",d]]);export{S as __pageData,P as default};
